import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';
import './ProposeWorkshopPage.css';

const WORKSHOPS = [
  { id: 1, name: 'Python', duration: 2, tnc: 'Computer lab with Python 3 installed required. Minimum 20 participants. FOSSEE reserves the right to reschedule.' },
  { id: 2, name: 'Scilab', duration: 3, tnc: 'Lab with Scilab 6.x installed required. Minimum 20 participants. No commercial use of the workshop material.' },
  { id: 3, name: 'OpenFOAM', duration: 5, tnc: 'Linux workstations with OpenFOAM 8+ required. Minimum 15 participants. Coordinator must arrange lab access for all 5 days.' },
  { id: 4, name: 'DWSIM', duration: 2, tnc: 'DWSIM installed on all lab systems. Minimum 20 participants. Chemical engineering lab preferred.' },
  { id: 5, name: 'eSim', duration: 3, tnc: 'eSim installed on lab systems. Minimum 20 participants. Electronics lab preferred.' },
  { id: 6, name: 'R', duration: 2, tnc: 'R and RStudio installed. Minimum 20 participants.' },
  { id: 7, name: 'Arduino', duration: 2, tnc: 'Arduino Uno kits provided by FOSSEE. Lab with USB access required. Minimum 15 participants.' },
  { id: 8, name: 'LaTeX', duration: 1, tnc: 'TeX Live or MiKTeX installed. Minimum 20 participants.' },
];

// Get min date: today + 3 days, exclude weekends
function getMinDate() {
  const d = new Date();
  d.setDate(d.getDate() + 3);
  while (d.getDay() === 0 || d.getDay() === 6) d.setDate(d.getDate() + 1);
  return d.toISOString().split('T')[0];
}

function getMaxDate() {
  const d = new Date();
  d.setFullYear(d.getFullYear() + 1);
  return d.toISOString().split('T')[0];
}

export default function ProposeWorkshopPage() {
  const { user, addToast } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({ workshopId: '', date: '', attendees: '', comments: '' });
  const [errors, setErrors] = useState({});
  const [tncOpen, setTncOpen] = useState(false);
  const [tncAccepted, setTncAccepted] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  if (!user) {
    return (
      <div className="container" style={{ padding: '80px 20px', textAlign: 'center' }}>
        <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔒</div>
        <h2>Sign in required</h2>
        <p style={{ color: 'var(--text-muted)', marginBottom: '24px' }}>
          You must be signed in to propose a workshop.
        </p>
        <div style={{ display: 'flex', gap: '12px', justifyContent: 'center', flexWrap: 'wrap' }}>
          <Link to="/login" className="btn btn-primary">Sign in</Link>
          <Link to="/register" className="btn btn-outline">Register</Link>
        </div>
      </div>
    );
  }

  const selectedWorkshop = WORKSHOPS.find(w => w.id === parseInt(form.workshopId));

  const validateStep1 = () => {
    const e = {};
    if (!form.workshopId) e.workshopId = 'Please select a workshop type';
    if (!form.date) e.date = 'Please select a date';
    return e;
  };

  const validateStep2 = () => {
    const e = {};
    if (!form.attendees || isNaN(form.attendees) || parseInt(form.attendees) < 15) {
      e.attendees = 'Minimum 15 attendees required';
    }
    if (!tncAccepted) e.tnc = 'You must accept the terms and conditions';
    return e;
  };

  const handleNext = () => {
    const errs = validateStep1();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    setErrors({});
    setStep(2);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validateStep2();
    if (Object.keys(errs).length) { setErrors(errs); return; }
    await new Promise(r => setTimeout(r, 800));
    setSubmitted(true);
    addToast('Workshop proposed successfully!', 'success');
  };

  const set = (field) => (e) => {
    setForm(p => ({ ...p, [field]: e.target.value }));
    if (errors[field]) setErrors(p => ({ ...p, [field]: null }));
  };

  if (submitted) {
    return (
      <div className="container" style={{ padding: '80px 20px', textAlign: 'center', maxWidth: '520px' }}>
        <div className="propose-success">
          <div className="propose-success-icon">✅</div>
          <h2>Workshop Proposed!</h2>
          <p style={{ color: 'var(--text-secondary)', marginBottom: '8px' }}>
            Your proposal for <strong style={{ color: 'var(--text-primary)' }}>{selectedWorkshop?.name}</strong> on{' '}
            <strong style={{ color: 'var(--text-primary)' }}>{form.date}</strong> has been submitted.
          </p>
          <p style={{ color: 'var(--text-muted)', fontSize: '14px', marginBottom: '32px' }}>
            The FOSSEE team will review your proposal and assign an instructor. You'll be notified via email.
          </p>
          <div style={{ display: 'flex', gap: '12px', justifyContent: 'center', flexWrap: 'wrap' }}>
            <Link to="/my-workshops" className="btn btn-primary">View My Workshops</Link>
            <button className="btn btn-outline" onClick={() => { setSubmitted(false); setStep(1); setForm({ workshopId:'', date:'', attendees:'', comments:'' }); setTncAccepted(false); }}>
              Propose Another
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="propose-page">
      <div className="container">
        <div className="page-header">
          <h1>Propose a Workshop</h1>
          <p>Request a FOSSEE workshop for your college or institute</p>
        </div>

        <div className="propose-layout">
          {/* Steps indicator */}
          <div className="propose-steps" role="list" aria-label="Progress steps">
            {[
              { n: 1, label: 'Select Workshop' },
              { n: 2, label: 'Confirm Details' },
            ].map(s => (
              <div
                key={s.n}
                className={`propose-step${step === s.n ? ' active' : ''}${step > s.n ? ' done' : ''}`}
                role="listitem"
                aria-current={step === s.n ? 'step' : undefined}
              >
                <div className="propose-step-num">{step > s.n ? '✓' : s.n}</div>
                <span className="propose-step-label">{s.label}</span>
              </div>
            ))}
            <div className="propose-step-line"></div>
          </div>

          {/* Form card */}
          <div className="propose-card card">
            {step === 1 && (
              <div className="propose-form-step">
                <h2 className="propose-step-title">Select Workshop Type & Date</h2>
                <div className="form-group">
                  <label className="form-label" htmlFor="workshopId">
                    Workshop Type <span aria-hidden="true" style={{ color: '#fc814a' }}>*</span>
                  </label>
                  <select
                    id="workshopId"
                    className={`form-control${errors.workshopId ? ' form-control-error' : ''}`}
                    value={form.workshopId}
                    onChange={set('workshopId')}
                    aria-invalid={!!errors.workshopId}
                  >
                    <option value="">Choose a workshop type…</option>
                    {WORKSHOPS.map(w => (
                      <option key={w.id} value={w.id}>
                        {w.name} ({w.duration} day{w.duration > 1 ? 's' : ''})
                      </option>
                    ))}
                  </select>
                  {errors.workshopId && <span className="form-error" role="alert">{errors.workshopId}</span>}
                </div>

                {selectedWorkshop && (
                  <div className="propose-workshop-preview">
                    <div className="propose-preview-label">Selected</div>
                    <div style={{ fontWeight: 600, fontFamily: 'var(--font-display)', color: 'var(--text-primary)' }}>
                      {selectedWorkshop.name}
                    </div>
                    <span className="badge badge-info">{selectedWorkshop.duration} Day{selectedWorkshop.duration > 1 ? 's' : ''}</span>
                    <button className="btn btn-ghost btn-sm" onClick={() => setTncOpen(true)} type="button">
                      View T&C →
                    </button>
                  </div>
                )}

                <div className="form-group">
                  <label className="form-label" htmlFor="date">
                    Preferred Start Date <span aria-hidden="true" style={{ color: '#fc814a' }}>*</span>
                  </label>
                  <input
                    id="date"
                    type="date"
                    className={`form-control${errors.date ? ' form-control-error' : ''}`}
                    value={form.date}
                    onChange={set('date')}
                    min={getMinDate()}
                    max={getMaxDate()}
                    aria-invalid={!!errors.date}
                  />
                  {errors.date && <span className="form-error" role="alert">{errors.date}</span>}
                  <span style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '5px', display: 'block' }}>
                    Date must be at least 3 working days from today. Weekends not available.
                  </span>
                </div>

                <div className="propose-form-footer">
                  <Link to="/workshop-types" className="btn btn-ghost">← Browse workshops</Link>
                  <button className="btn btn-primary" onClick={handleNext} type="button">
                    Continue →
                  </button>
                </div>
              </div>
            )}

            {step === 2 && (
              <form className="propose-form-step" onSubmit={handleSubmit} noValidate>
                <h2 className="propose-step-title">Confirm Details</h2>

                {/* Summary */}
                <div className="propose-summary">
                  <div className="propose-summary-row">
                    <span>Workshop</span>
                    <strong>{selectedWorkshop?.name}</strong>
                  </div>
                  <div className="propose-summary-row">
                    <span>Duration</span>
                    <strong>{selectedWorkshop?.duration} Day{selectedWorkshop?.duration > 1 ? 's' : ''}</strong>
                  </div>
                  <div className="propose-summary-row">
                    <span>Start Date</span>
                    <strong>{form.date}</strong>
                  </div>
                </div>

                <div className="form-group">
                  <label className="form-label" htmlFor="attendees">
                    Expected Number of Attendees <span aria-hidden="true" style={{ color: '#fc814a' }}>*</span>
                  </label>
                  <input
                    id="attendees"
                    type="number"
                    className={`form-control${errors.attendees ? ' form-control-error' : ''}`}
                    value={form.attendees}
                    onChange={set('attendees')}
                    placeholder="e.g. 35"
                    min="15"
                    max="200"
                    aria-invalid={!!errors.attendees}
                  />
                  {errors.attendees && <span className="form-error" role="alert">{errors.attendees}</span>}
                </div>

                <div className="form-group">
                  <label className="form-label" htmlFor="comments">Additional Notes (optional)</label>
                  <textarea
                    id="comments"
                    className="form-control"
                    value={form.comments}
                    onChange={set('comments')}
                    placeholder="Any specific requirements, preferred timings, or questions for the instructor…"
                    rows="3"
                    style={{ resize: 'vertical' }}
                  />
                </div>

                {/* TnC checkbox */}
                <div className={`propose-tnc-box${errors.tnc ? ' propose-tnc-error' : ''}`}>
                  <label className="propose-tnc-label">
                    <input
                      type="checkbox"
                      checked={tncAccepted}
                      onChange={e => {
                        setTncAccepted(e.target.checked);
                        if (errors.tnc) setErrors(p => ({ ...p, tnc: null }));
                      }}
                      aria-describedby={errors.tnc ? 'tnc-error' : undefined}
                    />
                    <span>
                      I have read and accept the{' '}
                      <button type="button" className="tnc-link" onClick={() => setTncOpen(true)}>
                        Terms & Conditions
                      </button>
                      {' '}for this workshop
                    </span>
                  </label>
                  {errors.tnc && <span className="form-error" id="tnc-error" role="alert">{errors.tnc}</span>}
                </div>

                <div className="propose-form-footer">
                  <button type="button" className="btn btn-ghost" onClick={() => setStep(1)}>← Back</button>
                  <button type="submit" className="btn btn-primary">
                    Submit Proposal ✓
                  </button>
                </div>
              </form>
            )}
          </div>
        </div>
      </div>

      {/* TnC Modal */}
      {tncOpen && selectedWorkshop && (
        <div className="modal-overlay" onClick={() => setTncOpen(false)} role="dialog" aria-modal="true" aria-labelledby="tnc-title">
          <div className="modal-box" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3 id="tnc-title">Terms & Conditions — {selectedWorkshop.name}</h3>
              <button className="modal-close" onClick={() => setTncOpen(false)} aria-label="Close">✕</button>
            </div>
            <div className="modal-body">
              <p>{selectedWorkshop.tnc}</p>
            </div>
            <div className="modal-footer">
              <button className="btn btn-primary" onClick={() => { setTncAccepted(true); setTncOpen(false); }}>
                Accept Terms
              </button>
              <button className="btn btn-ghost" onClick={() => setTncOpen(false)}>Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
